{
  "bug_id": "53441",
  "description": "HDA Intel sound stops working after suspend to RAM. Regression from v3.6.11 introduced in v3.7.1.",
  "root_cause_summary": "chip->polling_mode is set persistently by azx_rirb_get_response on codec communication timeout but is never reset in the resume path. After a hardware reset via azx_init_chip, the CORB/RIRB interrupt mechanism is fully re-initialized, making polling_mode stale. On subsequent resume cycles, the stale flag causes repeated timeouts, which then set chip->single_cmd=1. Once single_cmd=1, azx_init_chip skips azx_init_cmd_io entirely, leaving CORB/RIRB uninitialized and the sound controller permanently broken.",
  "fault_localization": [
    {
      "rank": 1,
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_resume",
      "line_start": 2539,
      "line_end": 2566,
      "faulty_lines": [2561],
      "explanation": "PRIMARY BUG: azx_resume calls azx_init_chip(chip, 1) at line 2561 without first resetting chip->polling_mode to 0. After the hardware is fully reset by azx_init_chip (which re-initializes CORB/RIRB via azx_init_cmd_io), the interrupt-driven response mechanism is functional again, but chip->polling_mode remains set from a prior timeout. This stale flag causes all subsequent codec I/O to use the polling path, which triggers further timeouts on resume, ultimately setting chip->single_cmd=1 and permanently disabling CORB/RIRB initialization on all future resumes.",
      "fix": "Add 'chip->polling_mode = 0;' immediately before the 'azx_init_chip(chip, 1);' call at line 2561."
    },
    {
      "rank": 2,
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_runtime_resume",
      "line_start": 2580,
      "line_end": 2588,
      "faulty_lines": [2586],
      "explanation": "SECONDARY BUG (same class): azx_runtime_resume also calls azx_init_chip(chip, 1) at line 2586 without resetting chip->polling_mode. For chipsets with AZX_DCAPS_PM_RUNTIME (e.g., Intel PCH/SCH 5 Series, PCI ID 0x8086:0x3b56), runtime PM is active. If azx_runtime_resume is invoked (e.g., triggered via azx_power_notify), it suffers the same stale-flag problem as azx_resume.",
      "fix": "Add 'chip->polling_mode = 0;' immediately before the 'azx_init_chip(chip, 1);' call at line 2586."
    },
    {
      "rank": 3,
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_rirb_get_response",
      "line_start": 863,
      "line_end": 958,
      "faulty_lines": [912, 951],
      "explanation": "CONTRIBUTING CODE: azx_rirb_get_response sets chip->polling_mode=1 (line 912) and chip->single_cmd=1 (line 951) as error-recovery fallbacks on codec communication timeout. These assignments are correct for run-time error recovery, but the flags are never cleared on resume. The real defect is the absence of a reset in the resume path (ranks 1 and 2), not the assignments here."
    },
    {
      "rank": 4,
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_init_chip",
      "line_start": 1209,
      "line_end": 1230,
      "faulty_lines": [1222, 1223],
      "explanation": "AMPLIFYING CODE: azx_init_chip checks 'if (!chip->single_cmd)' at line 1222 before calling azx_init_cmd_io. This guard is correct by design (single_cmd mode intentionally bypasses CORB/RIRB), but it means that once chip->single_cmd is set by azx_rirb_get_response and not reset before the next call to azx_init_chip, CORB/RIRB will never be re-initialized after that resume, leaving the HDA controller in an unrecoverable broken state."
    }
  ],
  "error_message_to_code_mapping": {
    "azx_get_response timeout, switching to polling mode": {
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_rirb_get_response",
      "line": 909,
      "sets": "chip->polling_mode = 1 (line 912)"
    },
    "No response from codec, disabling MSI": {
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_rirb_get_response",
      "line": 917,
      "sets": "chip->msi = 0 (line 923)"
    },
    "azx_get_response timeout, switching to single_cmd mode": {
      "file": "sound/pci/hda/hda_intel.c",
      "function": "azx_rirb_get_response",
      "line": 948,
      "sets": "chip->single_cmd = 1 (line 951)"
    }
  },
  "regression_context": {
    "broken_since": "v3.7.1",
    "last_good": "v3.6.11",
    "likely_cause_of_regression": "Runtime PM support (AZX_DCAPS_PM_RUNTIME) was added for Intel PCH/SCH chipsets in 3.7, introducing azx_runtime_suspend and azx_runtime_resume. The new PM code paths interact with the existing system sleep paths in ways that increase the likelihood of codec communication failures during resume, exposing the pre-existing absence of chip->polling_mode reset in the resume functions."
  }
}

